"""
4) Dada una lista con valores repetidos:

![image.png](data:image/png;base64,)

•Crear una nueva lista sin elementos repetidos.

•Mostrar el resultado.
"""

datos = [1, 3, 5, 3, 7, 1, 9, 5, 3]
listaNueva = []
for i in datos: # for para iterar los datos de la lista
  if i not in listaNueva: # pregunta si el dato iterado de la lista original no esta en la nueva lista nueva que creamos, si esto es verdadero lo agrega.
    listaNueva.append(i) # agrega el dato a la lista nueva

print(listaNueva)